mapper.select:
SELECT * FROM record_academic
WHERE student_id = #{studentId}
ORDER BY academic_year DESC

mapper.insert:
INSERT INTO record_academic (
    student_id, academic_year, course_nature, course_name, credit, gpa, score, is_invalidated, credit_gpa
) VALUES (
    #{studentId}, #{academicYear}, #{courseNature}, #{courseName}, #{credit}, #{gpa}, #{score}, #{isInvalidated}, #{creditGpa}
)

mapper.update:
UPDATE record_academic
academic_year = #{academicYear}, course_nature = #{courseNature}, course_name = #{courseName}, credit = #{credit}, gpa = #{gpa}, score = #{score}, is_invalidated = #{isInvalidated}, credit_gpa = #{creditGpa}
WHERE id = #{id}
